const query      = $('Feedback Form Webhook').first().json.query || {};
const orderId    = query.order_id    || '';
const email      = query.email       || '';
const friendName = query.friend_name || '';

const env        = $('Envs').first().json.env;
const submitBase = `https://evermagic.app.n8n.cloud/webhook${env.is_live ? '' : '-test'}`;
const submitUrl  = `${submitBase}/evermagic/uat-feedback-submit`;

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Quick feedback — EverMagic</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; }
    body { margin:0; padding:32px 16px; background:#0f0f1a; font-family:'Segoe UI',Roboto,Helvetica,Arial,sans-serif; color:#e8e8f5; }
    .card { max-width:520px; margin:0 auto; background:#16213e; border-radius:16px; padding:36px 32px; }
    h1 { margin:0 0 6px; font-size:22px; color:#fff; }
    .sub { margin:0 0 28px; font-size:14px; color:#8b8ba3; }
    label { display:block; font-size:12px; text-transform:uppercase; letter-spacing:1px; color:#b0b0cc; margin:20px 0 6px; }
    label:first-of-type { margin-top:0; }
    select, textarea {
      width:100%; background:#1e2a45; border:1px solid #2a3a5c;
      border-radius:8px; color:#e8e8f5; font-size:15px; padding:12px 14px;
      outline:none; font-family:inherit;
    }
    select { height:46px; }
    textarea { resize:vertical; min-height:88px; }
    select:focus, textarea:focus { border-color:#7c3aed; }
    .hint { font-size:12px; color:#8b8ba3; margin:4px 0 0; }
    button {
      display:block; width:100%; margin-top:28px;
      padding:14px; background:#7c3aed; color:#fff;
      font-size:16px; font-weight:700; border:none;
      border-radius:10px; cursor:pointer;
    }
    button:hover { background:#6d28d9; }
    .note { margin-top:16px; font-size:12px; color:#8b8ba3; text-align:center; }
    @media (max-width:560px) { .card { padding:28px 20px; } }
  </style>
</head>
<body>
  <div class="card">
    <h1>Quick feedback</h1>
    <p class="sub">5 questions — 2 minutes. Only Taras will see this.</p>
    <form method="POST" action="${submitUrl}">
      <input type="hidden" name="order_id"    value="${orderId}">
      <input type="hidden" name="email"        value="${email}">
      <input type="hidden" name="friend_name"  value="${friendName}">

      <label for="process_feedback">How was the process — ordering, waiting, receiving?</label>
      <textarea id="process_feedback" name="process_feedback" placeholder="Honest take on the experience..."></textarea>

      <label for="result_feedback">What did you think of the result — the PDFs?</label>
      <textarea id="result_feedback" name="result_feedback" placeholder="Story quality, illustrations, layout..."></textarea>

      <label for="open_feedback">Anything else — broken, missing, loved?</label>
      <textarea id="open_feedback" name="open_feedback" placeholder="Anything at all..."></textarea>

      <label for="would_buy">Would you buy this for a kid?</label>
      <textarea id="would_buy" name="would_buy">
              </textarea>

      <label for="price_expectation">What would you pay for this?</label>
      <textarea id="price_expectation" name="price_expectation" placeholder=""></textarea>


      <button type="submit">Send feedback</button>
    </form>
    <p class="note">Made with ❤️ by EverMagic — Taras</p>
  </div>
</body>
</html>`;

return [{ json: { html } }];

const raw = {};
for (const item of $input.all()) {
  raw[item.json.key] = item.json.value;
}
const env = {
  mode:    raw.mode,
  is_live: raw.mode === 'live',
};
return [{ json: { env } }];

const body =  $('Feedback Submit Webhook').first().json.body || $('Feedback Submit Webhook').first().json.body.json;

const feedback = {
  order_id:          body.order_id          || null,
  email:             body.email             || null,
  would_buy:         body.would_buy         || null,
  price_expectation: body.price_expectation || null,
  process_feedback:  body.process_feedback  || null,
  result_feedback:   body.result_feedback   || null,
  open_feedback:     body.open_feedback     || null,
};

const env      = $('Envs Submit').first().json.env;
const branch   = env.is_live ? 'main' : 'develop';
const logoUrl  = `https://raw.githubusercontent.com/TarasGolub/evermagic/${branch}/templates/icons/logo_email.png`;
const friendName = body.friend_name || 'there';

const thankyouTemplate = $('Fetch Thank-you Email Template').first().json.data;
const thankyouHtml = thankyouTemplate
  .replace(/\{\{logo_url\}\}/g,    logoUrl)
  .replace(/\{\{friend_name\}\}/g, friendName);

return [{
  json: {
    feedback,
    participant_email: feedback.email,
    to:      feedback.email,
    subject: `Got it, ${friendName} — thank you. Taras`,
    html:    thankyouHtml,
  }
}];

const rows = $('Fetch All Feedback').all().map(item => item.json);

if (rows.length === 0) throw new Error('No UAT feedback rows yet.');

const formatted = rows.map((r, i) => `
--- Respondent ${i + 1} (${r.email || 'unknown'}) ---
Would buy: ${r.would_buy || '(no answer)'}
Price expectation: ${r.price_expectation || '(no answer)'}
Process feedback: ${r.process_feedback || '(no answer)'}
Result feedback: ${r.result_feedback || '(no answer)'}
Open feedback: ${r.open_feedback || '(no answer)'}
`.trim()).join('\n\n');

const prompt = `
You are analyzing UAT feedback for EverMagic — an AI service that creates personalised storybooks for children (custom story, illustrations, coloring book, certificate). Sent free to ${rows.length} friends before a commercial Etsy launch.

Feedback from all respondents:

${formatted}

Produce a structured analysis:
1. **Overall sentiment** — 2–3 sentences.
2. **Would-buy breakdown** — count Yes/No/Maybe and what it signals.
3. **Price signal** — range mentioned and pricing implication.
4. **Top positives** — bullet list, max 5.
5. **Top problems / concerns** — bullet list, max 5.
6. **Top 5 improvements before launch** — ranked by impact, one-sentence rationale each.
7. **One-line launch recommendation** — go / go with caveats / hold, and why.

Be direct. Skip filler. Flag if feedback is thin or contradictory.
`.trim();

return [{ json: { prompt, respondent_count: rows.length } }];

const gptResponse = $input.first().json?.output[0]?.content[0]?.text
  || $('OpenAI').first().json.message?.content
                 || $('OpenAI').first().json.choices?.[0]?.message?.content
                 || '(no response)';

const latestFeedback  = $('Parse UAT Feedback').first().json.feedback;
const respondentCount = $('Build Synthesis Prompt').first().json.respondent_count;
const submitterEmail  = latestFeedback.email || 'unknown';

function row(label, value) {
  return `<tr>
    <td style="padding:5px 0;font-size:13px;color:#888;width:40%;vertical-align:top;">${label}</td>
    <td style="padding:5px 0;font-size:13px;color:#111;vertical-align:top;">${value || '<em style="color:#bbb">no answer</em>'}</td>
  </tr>`;
}

const individualHtml = `<table style="width:100%;border-collapse:collapse;">
  ${row('Would buy', latestFeedback.would_buy)}
  ${row('Price', latestFeedback.price_expectation)}
  ${row('Process', latestFeedback.process_feedback)}
  ${row('Result (PDFs)', latestFeedback.result_feedback)}
  ${row('Anything else', latestFeedback.open_feedback)}
</table>`;

function mdToHtml(text) {
  return text
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/^#{1,3}\s+(.+)/gm, '<strong style="font-size:14px;">$1</strong>')
    .replace(/^(\d+)\.\s+/gm, '<br><strong>$1.</strong> ')
    .replace(/^[-•]\s+/gm, '<br>• ')
    .replace(/\n{2,}/g, '</p><p style="margin:0 0 10px;font-size:14px;line-height:1.7;color:#333;">')
    .replace(/\n/g, '<br>');
}

const html = `
<div style="font-family:'Segoe UI',Roboto,sans-serif;max-width:680px;margin:0 auto;padding:32px 24px;color:#111;">
  <h2 style="margin:0 0 4px;font-size:20px;">🧪 UAT Feedback #${respondentCount}</h2>
  <p style="margin:0 0 24px;font-size:13px;color:#888;">From: ${submitterEmail} · ${new Date().toISOString().slice(0,10)}</p>
  <div style="background:#f9f9f9;border:1px solid #e5e7eb;border-radius:8px;padding:20px 24px;margin-bottom:28px;">
    <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#888;margin-bottom:12px;">This response</div>
    ${individualHtml}
  </div>
  <div style="border-left:3px solid #7c3aed;padding-left:20px;">
    <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#7c3aed;margin-bottom:12px;">
      AI summary — ${respondentCount} response${respondentCount !== 1 ? 's' : ''} so far
    </div>
    <p style="margin:0 0 10px;font-size:14px;line-height:1.7;color:#333;">${mdToHtml(gptResponse)}</p>
  </div>
</div>`.trim();

return [{
  json: {
    to:      'taras.evermagic@gmail.com',
    subject: `🧪 UAT #${respondentCount} — ${submitterEmail}`,
    html,
  }
}];

